export function getSearch(value, searchText) {
    return value !== undefined && value.toLowerCase().trim().includes(searchText.toLowerCase().trim())
}

export function debounce(cb,delay = 500) {
    let timer = null
    return function (...args) {
      clearTimeout(timer)
      timer = setTimeout(() => {
         cb.apply(this, args)
      }, delay)
    }
}
